import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Coins, ShieldCheck, Zap, Plus, History, X, Star, Save
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export default function Dashboard() {
  const navigate = useNavigate();
  const [myListings, setMyListings] = useState([]);
  const [isRatingModalOpen, setIsRatingModalOpen] = useState(false);
  
  // Rating State
  const [currentRating, setCurrentRating] = useState(4.9);
  const [newRatingInput, setNewRatingInput] = useState(5);

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem('myListings')) || [];
    setMyListings(saved);
    
    const savedRating = localStorage.getItem('userRating');
    if (savedRating) setCurrentRating(parseFloat(savedRating));
  }, []);

  const handleRecordRating = (e) => {
    e.preventDefault();
    // Logic to average the new rating with current (Simplified for prototype)
    const updatedRating = ((currentRating + parseFloat(newRatingInput)) / 2).toFixed(1);
    setCurrentRating(updatedRating);
    localStorage.setItem('userRating', updatedRating);
    setIsRatingModalOpen(false);
  };

  return (
    <div className="p-10 space-y-10">
      {/* 1. HEADER - Cleaned up version */}
      <div className="flex justify-between items-center">
        <h1 className="text-4xl font-black text-slate-900 dark:text-white tracking-tight">Dashboard</h1>
        <button 
          onClick={() => navigate('/create')}
          className="bg-teal-600 text-white px-8 py-4 rounded-2xl font-bold flex items-center gap-2 hover:bg-teal-700 shadow-lg shadow-teal-600/20 transition-all active:scale-95"
        >
          <Plus size={20} /> New Listing
        </button>
      </div>

      {/* 2. STAT CARDS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="bg-teal-600 p-10 rounded-[40px] text-white shadow-2xl relative overflow-hidden">
          <Coins className="mb-6 opacity-80" size={32} />
          <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-80">Available Balance</p>
          <h2 className="text-5xl font-black mt-2">1,450 <span className="text-lg opacity-60">WTK</span></h2>
        </div>

        {/* INTERACTIVE RATING CARD */}
        <button 
          onClick={() => setIsRatingModalOpen(true)}
          className="text-left bg-white dark:bg-slate-900 p-10 rounded-[40px] border border-slate-50 dark:border-slate-800 shadow-sm transition-all hover:border-teal-500/50 group"
        >
          <ShieldCheck className="mb-6 text-teal-600 group-hover:scale-110 transition-transform" size={32} />
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Trust Rating</p>
          <h2 className="text-4xl font-black mt-2 dark:text-white">{currentRating}<span className="text-lg text-slate-300">/5.0</span></h2>
          <p className="text-[10px] text-teal-600 font-bold mt-2 uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">Click to record rating</p>
        </button>

        <div className="bg-white dark:bg-slate-900 p-10 rounded-[40px] border border-slate-50 dark:border-slate-800 shadow-sm">
          <Zap className="mb-6 text-yellow-500" size={32} />
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Active Barters</p>
          <h2 className="text-4xl font-black mt-2 dark:text-white">08</h2>
        </div>
      </div>

      {/* 3. LISTINGS */}
      <section className="space-y-6">
        <h3 className="text-2xl font-black text-slate-900 dark:text-white">My New Listings</h3>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          {myListings.map((item) => (
            <div key={item.id} className="bg-white dark:bg-slate-900 p-8 rounded-[40px] border border-slate-50 dark:border-slate-800 shadow-sm">
              <h4 className="text-lg font-bold text-slate-900 dark:text-white truncate">{item.title}</h4>
              <p className="text-teal-600 font-black mt-2">{item.wtk} WTK</p>
            </div>
          ))}
        </div>
      </section>

      {/* RATING RECORDER MODAL */}
      <AnimatePresence>
        {isRatingModalOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-950/60 backdrop-blur-md">
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }}
              className="bg-white dark:bg-slate-900 w-full max-w-sm rounded-[40px] p-10 shadow-2xl border border-slate-100 dark:border-slate-800"
            >
              <div className="flex justify-between items-center mb-8">
                <h2 className="text-2xl font-black dark:text-white">Record Rating</h2>
                <button onClick={() => setIsRatingModalOpen(false)} className="text-slate-400"><X size={24} /></button>
              </div>

              <form onSubmit={handleRecordRating} className="space-y-6">
                <div>
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-2">New Feedback Score</label>
                  <div className="flex gap-2 mt-4">
                    {[1, 2, 3, 4, 5].map((star) => (
                      <button 
                        key={star} 
                        type="button"
                        onClick={() => setNewRatingInput(star)}
                        className={`flex-1 py-4 rounded-2xl transition-all ${newRatingInput >= star ? 'bg-teal-600 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}
                      >
                        <Star size={20} className="mx-auto" fill={newRatingInput >= star ? "currentColor" : "none"} />
                      </button>
                    ))}
                  </div>
                </div>

                <button type="submit" className="w-full bg-teal-600 text-white py-5 rounded-2xl font-black text-lg flex items-center justify-center gap-3 shadow-lg hover:bg-teal-700 transition-all">
                  <Save size={20} /> Update Trust Score
                </button>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}
